code.C:
#include <stdio.h>
#include <math.h>

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        double base = 0.143 * N;
        double val = pow(base, N);
        long long ans = (long long)floor(val + 0.5);
        printf("%lld\n", ans);
    }
    return 0;
}

